In the `upgradeTo` function, validate that the new implementation address has code before setting it. This can be done using an `extcodesize` check. This ensures the proxy can only point to valid, deployed contracts.

```solidity
function upgradeTo(address implementation) public virtual onlyProxyOwner {
    address currentImplementation;
    bytes32 position = implementationPosition;
    assembly {
        currentImplementation := sload(position)
    }
    require(currentImplementation != implementation);

    // Add validation check
    uint256 codeSize;
    assembly {
        codeSize := extcodesize(implementation)
    }
    require(codeSize > 0, "Implementation must be a contract");

    assembly {
        sstore(position, implementation)
    }
    emit Upgraded(implementation);
}
```

