vulnerabilities.recommendation:
Strictly follow the Checks-Effects-Interactions (CEI) pattern. Move all state-modifying operations, including the `_mint` call, before the external `burnFrom` call. Alternatively, add a `nonReentrant` modifier to the `swap` function to prevent re-entrancy attacks entirely.

```solidity
// Corrected Code
function swap(address token, uint256 amount) public nonReentrant { // Added nonReentrant guard
    require(isContract(token), "Token is not a contract.");
    require(
        swapTokens[token].tokenContract != address(0),
        "Swap token is not a contract."
    );
    require(
        amount <= swapTokens[token].supply,
        "Swap amount is more than supply."
    );

    // --- EFFECTS ---
    swapTokens[token].supply = swapTokens[token].supply - amount;
    _mint(msg.sender, amount);

    // --- INTERACTION ---
    ERC20Burnable swapToken = ERC20Burnable(
        swapTokens[token].tokenContract
    );
    swapToken.burnFrom(msg.sender, amount);

    emit Swap(token, amount);
}
```

